class ConsistentHash {
  constructor(vnodes = 150) {
    this.vnodes = vnodes;
    this.ring = new Map(); // hash → node
    this.sortedHashes = [];
    this.nodes = new Set();
  }
  _hash(key) {
    let h = 0;
    for (let i = 0; i < key.length; i++) {
      h = ((h << 5) - h) + key.charCodeAt(i);
      h |= 0;
    }
    return h;
  }
  addNode(node) {
    this.nodes.add(node);
    for (let i = 0; i < this.vnodes; i++) {
      const hash = this._hash(`${node}:vnode:${i}`);
      if (!this.ring.has(hash)) {
        this.ring.set(hash, node);
        this.sortedHashes.push(hash);
      }
    }
    this.sortedHashes.sort((a, b) => a - b);
  }
  getNode(key) {
    if (this.sortedHashes.length === 0) return null;
    const hash = this._hash(key);
    let idx = this.lowerBound(hash);
    if (idx === this.sortedHashes.length) idx = 0;
    return this.ring.get(this.sortedHashes[idx]);
  }
  lowerBound(target) {
    let lo = 0, hi = this.sortedHashes.length;
    while (lo < hi) {
      const mid = Math.floor((lo + hi) / 2);
      if (this.sortedHashes[mid] < target) lo = mid + 1;
      else hi = mid;
    }
    return lo;
  }
  removeNode(node) {
    this.nodes.delete(node);
    for (let i = 0; i < this.vnodes; i++) {
      const hash = this._hash(`${node}:vnode:${i}`);
      if (this.ring.has(hash)) {
        this.ring.delete(hash);
        const idx = this.sortedHashes.indexOf(hash);
        if (idx > -1) this.sortedHashes.splice(idx, 1);
      }
    }
  }
}

const BASE62 = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz";

function base62Encode(num) {
  if (num === 0) return BASE62[0];
  let result = "";
  while (num > 0) {
    result = BASE62[num % 62] + result;
    num = Math.floor(num / 62);
  }
  return result;
}

// KGS: pre-generate keys to avoid DB contention on ID generation
class KGS {
  constructor() {
    this.counter = Date.now() * 1000; // timestamp-based start
    this.batch = [];
    this.batchSize = 10000;
  }
  getNextKey() {
    if (this.batch.length === 0) {
      this.refillBatch();
    }
    return this.batch.pop();
  }
  refillBatch() {
    for (let i = 0; i < this.batchSize; i++) {
      this.batch.push(base62Encode(this.counter++));
    }
  }
}

// 7 chars of Base62 = 62^7 ≈ 3.5 trillion unique keys
// Performance: nanoseconds per encoding, batch of 10K keys uses ~100KB memory
